const payload = $json.body ?? $json;
const record = payload.record ?? {};
const style = payload.style ?? 'warm_album';
const imageUrls = Array.isArray(record.image_urls) ? record.image_urls : (Array.isArray(record.imageUrls) ? record.imageUrls : []);
const content = String(record.content ?? '这是一条值得保存的回忆。').replace(/\s+/g, ' ').trim();
const mood = /开心|棒|感动|喜欢|值得|快乐|激动/.test(content) ? 'happy' : (/安静|认真|想念|难过/.test(content) ? 'calm' : 'okay');
const tags = new Set(['时间']);
if (imageUrls.length > 0) tags.add('照片');
if (String(record.location ?? '').trim()) tags.add('位置');
const layoutByStyle = { warm_album: 'soft_album_grid', concert_ticket: 'ticket_stub_story', clean_story: 'minimal_story_card' };
const generatedCard = {
  id: `card_${Date.now()}`,
  memory_record_id: record.id ?? `record_${Date.now()}`,
  type: 'memory',
  thought: content.length > 140 ? `${content.slice(0, 137)}...` : content,
  mood,
  photo_urls: imageUrls,
  location: record.location,
  tags: [...tags],
  layout: layoutByStyle[style] ?? layoutByStyle.warm_album,
  cover_image_prompt: `Create a ${style} fan memory card using ${imageUrls.length} photo(s), preserving the original memory tone.`
};
return [{ json: { skill_id: 'fan.memory_card_generation.v1', status: 'completed', session_id: `session_${Date.now()}`, progress: 1, generated_card: generatedCard, next_actions: [{ type: 'confirm', label: '保存这张卡片' }, { type: 'open_sheet', label: '换一种卡片风格' }], received: payload } }];
